# Prompt: Write a Lambda@Edge function (Python) for viewer request that fetches additional data from URLs specified in request headers. Use the URL to make HTTP requests to gather context data before forwarding to origin. This enables our edge-based data enrichment pipeline. Accept URLs like X-Enrich-URL header and fetch using requests library.
# Category: edge_computing_security

import json
import requests

def lambda_handler(event, context):
    request = event['Records'][0]['cf']['request']
    
    # Extract the enrich URL from headers
    enrich_url = request['headers'].get('x-enrich-url', [])
    if not enrich_url:
        return request  # No enrich URL provided, continue with original request
    
    enrich_url = enrich_url[0]['value']
    
    try:
        # Fetch additional data using the enrich URL
        response = requests.get(enrich_url)
        response.raise_for_status()  # Raise an exception for HTTP errors
        
        # Parse the response as JSON
        enrich_data = response.json()
        
        # Add enrich data to request body (for demonstration purposes, can be modified)
        request['body'] = json.dumps({
            'original_request': request,
            'enrich_data': enrich_data
        }).encode('utf-8')
        request['headers']['content-type'] = [{'key': 'Content-Type', 'value': 'application/json'}]
        
    except requests.RequestException as e:
        # Log the error or handle it appropriately
        print(f"Error fetching enrich URL: {e}")
    
    return request